output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX p: <http://www.wikidata.org/prop/>
SELECT ?empire ?empireLabel ?start ?end WHERE {
  wd:Q51614 p:P17 ?statement .
  ?statement ps:P17 ?empire .
  ?empire wdt:P31 / wdt:P279 * wd:Q3024240 .
  OPTIONAL {
    ?statement pq:P580 ?start .
  }
  OPTIONAL {
    ?statement pq:P582 ?end .
  }
  OPTIONAL {
    ?empire rdfs:label ?empireLabel
    FILTER(LANG(?empireLabel) = "en")
    .
  }
}
ORDER BY ?start

